<?php namespace App\Repositories\Transport;use App\Repositories\BaseRepository;use App\Models\Transport\TransportDriver;use Illuminate\Database\Eloquent\Collection;class TransportDriverRepository extends BaseRepository{    public function __construct(TransportDriver $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByLicenseNo(string $licenseNo): ?TransportDriver    {        return $this->query()->where('license_no', $licenseNo)->first();    }    public function findByName(string $name): Collection    {        return $this->query()->where('first_name', 'like', "%{$name}%")->orWhere('last_name', 'like', "%{$name}%")->get();    }    public function getActiveDrivers(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getAvailableDrivers(): Collection    {        return $this->query()->where('is_active', true)->where('status', 'available')->get();    }    public function searchDrivers(string $keyword): Collection    {        return $this->query()->where('first_name', 'like', "%{$keyword}%")->orWhere('last_name', 'like', "%{$keyword}%")->orWhere('phone', 'like', "%{$keyword}%")->orWhere('license_no', 'like', "%{$keyword}%")->get();    }    public function getLicenseExpiringSoon(int $days = 30): Collection    {        return $this->query()->where('license_expiry', '>=', now())->where('license_expiry', '<=', now()->addDays($days))->get();    }    public function getByExperience(int $minYears): Collection    {        return $this->query()->where('experience_years', '>=', $minYears)->get();    }    public function assignVehicle(int $driverId, int $vehicleId): bool    {        return $this->update($driverId, ['vehicle_id' => $vehicleId]);    }}